import {
    AmbientLight,
    Color,
    CubeTextureLoader,
    DirectionalLight,
    Euler,
    MathUtils,
    Quaternion,
    Vector3,
} from 'three';
import { MapControls } from 'three/examples/jsm/controls/MapControls.js';

import Instance from '@giro3d/giro3d/core/Instance.js';
import Extent from '@giro3d/giro3d/core/geographic/Extent.js';
import ColorLayer from '@giro3d/giro3d/core/layer/ColorLayer.js';
import ElevationLayer from '@giro3d/giro3d/core/layer/ElevationLayer.js';
import Map from '@giro3d/giro3d/entities/Map.js';
import OrientedImageCollection from '@giro3d/giro3d/entities/OrientedImageCollection.js';
import BilFormat from '@giro3d/giro3d/formats/BilFormat.js';
import Inspector from '@giro3d/giro3d/gui/Inspector.js';
import WmtsSource from '@giro3d/giro3d/sources/WmtsSource.js';

import StatusBar from './widgets/StatusBar.js';
import CoordinateSystem from '@giro3d/giro3d/core/geographic/coordinate-system/CoordinateSystem.js';

Instance.registerCRS(
    'EPSG:2154',
    '+proj=lcc +lat_0=46.5 +lon_0=3 +lat_1=49 +lat_2=44 +x_0=700000 +y_0=6600000 +ellps=GRS80 +towgs84=0,0,0,0,0,0,0 +units=m +no_defs +type=crs',
);
Instance.registerCRS(
    'IGNF:WGS84G',
    'GEOGCS["GCS_WGS_1984",DATUM["D_WGS_1984",SPHEROID["WGS_1984",6378137.0,298.257223563]],PRIMEM["Greenwich",0.0],UNIT["Degree",0.0174532925199433]]',
);

const SKY_COLOR = new Color(0xf1e9c6);

const instance = new Instance({
    target: 'view',
    crs: CoordinateSystem.fromEpsg(2154),
    backgroundColor: SKY_COLOR,
});

// create a map
const extent = new Extent(
    instance.coordinateSystem,
    -111629.52,
    1275028.84,
    5976033.79,
    7230161.64,
);
const map = new Map({
    extent,
    backgroundColor: 'gray',
    lighting: {
        enabled: true,
        elevationLayersOnly: true,
    },
    discardNoData: true,
});
instance.add(map);

const noDataValue = -1000;

const capabilitiesUrl =
    'https://data.geopf.fr/wmts?SERVICE=WMTS&VERSION=1.0.0&REQUEST=GetCapabilities';

WmtsSource.fromCapabilities(capabilitiesUrl, {
    layer: 'ELEVATION.ELEVATIONGRIDCOVERAGE.HIGHRES',
    format: new BilFormat(),
    noDataValue,
})
    .then(elevationWmts => {
        map.addLayer(
            new ElevationLayer({
                name: 'wmts_elevation',
                extent: map.extent,
                // We don't need the full resolution of terrain because we are not using any shading
                resolutionFactor: 1 / 8,
                minmax: { min: 0, max: 5000 },
                noDataOptions: {
                    replaceNoData: false,
                },
                source: elevationWmts,
            }),
        );
    })
    .catch(console.error);

WmtsSource.fromCapabilities(capabilitiesUrl, {
    layer: 'HR.ORTHOIMAGERY.ORTHOPHOTOS',
})
    .then(orthophotoWmts => {
        map.addLayer(
            new ColorLayer({
                name: 'wmts_orthophotos',
                extent: map.extent,
                source: orthophotoWmts,
            }),
        );
    })
    .catch(console.error);

const lookAt = new Vector3(913349.4056410324, 6456427.318278126, 1655.5296087248717);
instance.view.camera.position.set(lookAt.x, lookAt.y - 1000, lookAt.z + 500);
instance.view.camera.lookAt(lookAt);
instance.notifyChange(instance.view.camera);

const controls = new MapControls(instance.view.camera, instance.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.2;
controls.target.copy(lookAt);
controls.saveState();
instance.view.setControls(controls);

const cubeTextureLoader = new CubeTextureLoader();
cubeTextureLoader.setPath('image/skyboxsun25deg_zup/');
const cubeTexture = cubeTextureLoader.load([
    'px.jpg',
    'nx.jpg',
    'py.jpg',
    'ny.jpg',
    'pz.jpg',
    'nz.jpg',
]);

instance.scene.background = cubeTexture;

const dirLight = new DirectionalLight(0xffffff, 2);
dirLight.position.set(1, 1, 1).normalize();
dirLight.updateMatrixWorld(true);
instance.add(dirLight);

instance.add(new AmbientLight(0xffffff, 0.5));

const orientedImageCollection = new OrientedImageCollection({
    locationSpheres: {
        visible: true,
        radius: 5,
        color: 0xff0000,
    },
    frustums: {
        visible: true,
        color: 0x00ff00,
    },
    images: {
        visible: true,
    },
    source: {
        images: [
            {
                position: { x: 913349.4, y: 6456527.3, z: 1655.5 },
                orientation: { azimuth: 63.43494882292202, pitch: 0, roll: 0 },
                fov: 30,
                aspectRatio: 2.1041433370660694,
                imageUrl:
                    'data:image/webp;base64,',
                distance: 75,
            },
            {
                position: { x: 913349.4075213772, y: 6456327.324370834, z: 1655.5394783001393 },
                orientation: {
                    azimuth: -63.43494872435035,
                    pitch: 3.579554838952819e-8,
                    roll: 179.99999998210222,
                },
                fov: 30,
                aspectRatio: 2.1041433370660694,
                imageUrl:
                    'data:image/webp;base64,',
                distance: 75,
            },
            {
                position: { x: 913249.4075213753, y: 6456427.324370836, z: 1655.5394783001393 },
                orientation: {
                    azimuth: 1.0672169005165302e-7,
                    pitch: 63.434948761702955,
                    roll: 89.99999988068154,
                },
                fov: 30,
                aspectRatio: 2.1041433370660694,
                imageUrl:
                    'data:image/webp;base64,',
                distance: 75,
            },
            {
                position: { x: 913449.4075213767, y: 6456427.324370835, z: 1655.5394782992078 },
                orientation: {
                    azimuth: 2.1344338765256876e-7,
                    pitch: -63.43494882039993,
                    roll: -89.9999997613631,
                },
                fov: 30,
                aspectRatio: 2.1041433370660694,
                imageUrl:
                    'data:image/webp;base64,',
                distance: 75,
            },
        ],
    },
});
instance.add(orientedImageCollection);
console.log(orientedImageCollection.getBoundingBox());

Inspector.attach('inspector', instance, { title: 'main' });

StatusBar.bind(instance);
